-- ============================================
-- Legislacao full-site: joao-roma / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/204576
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = joao-roma-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 83
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=204576, tipo Deputado(a), ordemAssinatura=1.
-- 17 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'joao-roma';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'joao-roma: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao joao-roma: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2320595', '2333429', '2332255', '2320574', '2267407', '2265438', '2258955', '2258949', '2249196', '2245564', '2244967', '2241613', '2241608', '2241460', '2241455', '2241335', '2241298', '2241208', '2267367', '2264113', '2259256', '2258954', '2258891', '2248368', '2245563', '2243547', '2241612', '2241607', '2241459', '2241454', '2241334', '2241297', '2241207', '2258952', '2253623', '2246509', '2245511', '2243134', '2241610', '2241605', '2241457', '2241337', '2241300', '2241210', '2241203', '2320482', '2265439', '2259378', '2258956', '2258950', '2252144', '2246424', '2245510', '2241614', '2241609', '2241604', '2241456', '2241336', '2241299', '2241209', '2241202', '2267098', '2258959', '2258953', '2246521', '2245512', '2243136', '2241611', '2241606', '2241458', '2241453', '2241301', '2241296', '2241206', '2258957', '2320488', '2263612', '2320484', '2259258', '2320588', '2320563', '2320592', '2258769');
  IF target_present <> 83 THEN
    RAISE EXCEPTION 'Pre-condicao joao-roma: esperadas 83 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2320595', '2333429', '2332255', '2320574', '2267407', '2265438', '2258955', '2258949', '2249196', '2245564', '2244967', '2241613', '2241608', '2241460', '2241455', '2241335', '2241298', '2241208', '2267367', '2264113', '2259256', '2258954', '2258891', '2248368', '2245563', '2243547', '2241612', '2241607', '2241459', '2241454', '2241334', '2241297', '2241207', '2258952', '2253623', '2246509', '2245511', '2243134', '2241610', '2241605', '2241457', '2241337', '2241300', '2241210', '2241203', '2320482', '2265439', '2259378', '2258956', '2258950', '2252144', '2246424', '2245510', '2241614', '2241609', '2241604', '2241456', '2241336', '2241299', '2241209', '2241202', '2267098', '2258959', '2258953', '2246521', '2245512', '2243136', '2241611', '2241606', '2241458', '2241453', '2241301', '2241296', '2241206', '2258957', '2320488', '2263612', '2320484', '2259258', '2320588', '2320563', '2320592', '2258769')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'joao-roma-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao joao-roma: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao joao-roma: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

